import '../models/song.dart';

class MusicRepository {
  List<Song> fetchSongs() {
    return _allSongs;
  }

  List<String> getArtists() {
    final artists = _allSongs.map((s) => s.artist).toSet().toList();
    artists.sort();
    return artists;
  }

  List<Song> getSongsByArtist(String artistName) {
    return _allSongs.where((s) => s.artist == artistName).toList();
  }

  List<String> getAlbumsByArtist(String artistName) {
    final albums = getSongsByArtist(artistName).map((s) => s.album).toSet().toList();
    albums.sort();
    return albums;
  }

  List<Song> getSongsByAlbum(String artistName, String albumName) {
    return _allSongs.where((s) => s.artist == artistName && s.album == albumName).toList();
  }

  Song? getSongById(String songId) {
    try {
      return _allSongs.firstWhere((s) => s.id == songId);
    } catch (_) {
      return null;
    }
  }

  List<Song> searchSongs(String query) {
    final q = query.toLowerCase();
    return _allSongs.where((s) =>
      s.title.toLowerCase().contains(q) ||
      s.artist.toLowerCase().contains(q) ||
      s.album.toLowerCase().contains(q)
    ).toList();
  }

  int get songCount => _allSongs.length;

